#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e3+5;
int m[MAXN][MAXN];
int mxi[MAXN][MAXN],mni[MAXN][MAXN],mxj[MAXN][MAXN],mnj[MAXN][MAXN];
int a,b,n,ans=inf;
deque<int> q;
signed main(void)
{
    a=read(),b=read(),n=read();
    FOR(i,1,a)
    {
        FOR(j,1,b)
        {
            m[i][j]=read();
        }
    }
    FOR(i,1,a)
    {
        q.clear();
        FOR(j,1,b)
        {
            wh(!q.empty()&&q.front()<j-n+1)q.pop_front();
            wh(!q.empty()&&m[i][q.back()]<=m[i][j])q.pop_back();
            q.pb(j);
            if(j>=n)mxi[i][j-n+1]=m[i][q.front()];
        }
        q.clear();
        FOR(j,1,b)
        {
            wh(!q.empty()&&q.front()<j-n+1)q.pop_front();
            wh(!q.empty()&&m[i][q.back()]>=m[i][j])q.pop_back();
            q.pb(j);
            if(j>=n)mni[i][j-n+1]=m[i][q.front()];
        }
    }
    FOR(j,1,b-n+1)
    {
        q.clear();
        FOR(i,1,a)
        {
            wh(!q.empty()&&q.front()<i-n+1)q.pop_front();
            wh(!q.empty()&&mxi[q.back()][j]<=mxi[i][j])q.pop_back();
            q.pb(i);
            if(i>=n)mxj[i-n+1][j]=mxi[q.front()][j];
        }
        q.clear();
        FOR(i,1,a)
        {
            wh(!q.empty()&&q.front()<i-n+1)q.pop_front();
            wh(!q.empty()&&mni[q.back()][j]>=mni[i][j])q.pop_back();
            q.pb(i);
            if(i>=n)mnj[i-n+1][j]=mni[q.front()][j];
        }
    }
    FOR(i,1,a-n+1)
    {
        FOR(j,1,b-n+1)
        {
            ans=min(ans,mxj[i][j]-mnj[i][j]);
        }
    }
    write(ans);
    return false;
}
